Example
main()
{
  blob target;
  int len, pos;
  string s;
  anytype value;
  bool bigendian;
  s = "FFAB003AFF";
  target = s;
  DebugN(target);
  len = 1;
  value = 5;
  bigendian = TRUE;
  DebugN("Blob AppendValue : " + blobAppendValue( target,
  value, len, bigendian ));
//length of blob is 6 = FF AB 0 3A FF 5
  DebugN(target);
//ff ab 0 3a ff 5
}

