The function waits for a certain time (timeout) for a value change that
                fulfills the condition and returns the values ofdpNamesReturnvia the
                parameterreturnValues. If thetimeoutexpires,returnValuesare not affected. The function allows a type ofdpConnect()to several data
                points at the same time. This means that limited queries of datapoint values are
                possible, or if no condition is set, the values of other DPEs are returned if
                changes are made todpNamesWait.
Note that the function cannot be executed if the condition is already fulfilled when
                calling the function and no value change occurs on any of the named datapoint
                elements. Thus, the function waits for an value change that fulfills the
                condition.
Example
A child panel is to be opened, then the program waits for 5 seconds to see whether
                the value fulfills the condition "child.pnl" (either OK or cancel). The child panel
                contains buttons which set values when you click them. If this value is "child.pnl"
                (either OK or cancel), the condition is fulfilled. The datapoint that sets the
                value and the associated value are returned.
main()
{
  time t;
  dyn_string dpNamesWait, dpNamesReturn;
  dyn_anytype conditions, returnValues;
  int status;
  // assignment of the datapoints for dpNamesWait
  dpNamesWait =
  makeDynString("_PanelOff.PanelName:_original.._value");
  // indication of the condition that must be fulfilled
  conditions[1] = "child.pnl";
  // assignment of the datapoints for dpNamesReturn (data
  points
  // of the child panel that is parameterised for buttons
  dpNamesReturn = makeDynString(
  "_PanelOff.PanelName:_original.._value" );
  // timeout
  t = 5;
  // The child panel is opened
  ChildPanelOn( "child.pnl", "child", "", 0, 0 );
  // The function is called
  status = dpWaitForValue( dpNamesWait, conditions, dpNamesReturn,
  returnValues, t );
  // Clears the value of the DP
  dpSet( "System1:_PanelOff.PanelName:_original.._value","" );
  if ( status == -1 )
  {
    DebugN( "Error" );
    DebugN( "dpNamesWait : " + dpNamesWait );
    DebugN( "conditions : " + conditions );
    DebugN( "dpNamesReturn : " + dpNamesReturn );
    DebugN( "returnValues : " + returnValues );
  }
  else if ( dynlen(getLastError()) != 0 )
  {
    DebugN( "Error returned in message" );
    // Reaction: , for example, output
    DebugN( getLastError() );
    DebugN( "dpNamesWait : " + dpNamesWait );
    DebugN( "conditions : " + conditions );
    DebugN( "dpNamesReturn : " + dpNamesReturn );
    DebugN( "returnValues : " + returnValues );
  }
  else
  {
    DebugN( "everything ok" );
    DebugN( "dpNamesWait : " + dpNamesWait );
    DebugN( "conditions : " + conditions );
    DebugN( "dpNamesReturn : " + dpNamesReturn );
    DebugN( "returnValues : " + returnValues );
  }
}

Appends y or all elements of y, provided that y is a dynamic field, to the field x. y
                may also be a dynamic field. In this case y is emptied and appended to x. y then
                does not contain any elements. The data type of y must match that of x if y is a
                dynamic field. If y is not a dynamic type, i.e. a simple value, y is converted
                automatically to the data type of x.
To append values without changing the source variable please refer todynAppendConst().
Example
Adding 8 to the field {3,4,5,6,7}.
main()
{
  dyn_int x, y;
  x = makeDynInt(3,4,5,6,7);
  dynAppend(x, 8);
  DebugN(x);
}
Example
main()
{
  dyn_string dsDPE, dsValues;
  dyn_string dsNullValue = makeDynString("Null");
  dyn_anytype atValues;
  DebugN("First loop");
  for (int i = 1; i <= 5; i++)
  {
    dynAppend(dsDPE, "Value" + i);
    dynAppend(dsValues, dsNullValue );
  }
  //dynAppend(dynTarget, dynSource) will CUT (not copy) the array
  from dynSource, so the second loop uses an empty dyn_string (no
  elements)
  //To the second element anything is added -> the array
  dsNullValue is empty
  DebugN("dsDPE", dsDPE, "dsValues", dsValues, "dsNullValue",
  dsNullValue);
  /*
  ["dsDPE"][dyn_string 5 items
  1: "Value1"
  2: "Value2"
  3: "Value3"
  4: "Value4"
  5: "Value5"
  ]
  ["dsValues"]
  [dyn_string 1 items
  1: "Null"
  ]
  ["dsNullValue"]
  [dyn_string 0 items ]
  */
  DebugN("Second loop");
  for (int i = 1; i <= 5; i++)
  {
    dsDPE[i] = "Value" + i;
    dsValues[i] = dsNullValue;
  }
  //assign an empty dyn_string to a dyn_string -> the
  dyn_string will be casted to a string and added
  DebugN("dsDPE", dsDPE, "dsValues", dsValues);
  /*
  ["dsDPE"][dyn_string 5 items
  1: "Value1"
  2: "Value2"
  3: "Value3"
  4: "Value4"
  5: "Value5"
  ]
  ["dsValues"]
  [dyn_string 5 items
  1: ""
  2: ""
  3: ""
  4: ""
  5: ""
  ]
  */
  DebugN("Third loop");
  for (int i = 1; i <= 5; i++)
  {
    dsDPE[i] = "Value" + i;
    atValues[i] = dsNullValue ;
  }
  //an anytype can be anything, also an array, so each entry will
  be casted to an dyn_string (which is empty, due to first
  loop)
  DebugN("dsDPE", dsDPE, "dsValues", atValues);
  /*
  ["dsDPE"]
  [dyn_string 5 items
  1: "Value1"
  2: "Value2"
  3: "Value3"
  4: "Value4"
  5: "Value5"
  ]
  ["dsValues"]
  [dyn_anytype 5 items
  1: dyn_string 0 items
  2: dyn_string 0 items
  3: dyn_string 0 items
  4: dyn_string 0 items
  5: dyn_string 0 items
  ]
  */
  DebugN("Fourth loop");
  dsNullValue = makeDynString("AnEmptyValueNotNull");
  for (int i = 1; i <= 5; i++)
  {
    dsDPE[i] = "Value" + i;
    atValues[i] = dsNullValue;
  }
  //an anytype can be anything, also an array, so each entry will
  be casted to an dyn_string
  DebugN("dsDPE", dsDPE, "dsValues", atValues);
  /*
  ["dsDPE"]
  [dyn_string 5 items
  1: "Value1"
  2: "Value2"
  3: "Value3"
  4: "Value4"
  5: "Value5"
  ]
  ["dsValues"]
  [dyn_anytype 5 items
  1: dyn_string 1 items
  1: "AnEmptyValueNotNull"
  2: dyn_string 1 items
  1: "AnEmptyValueNotNull"
  3: dyn_string 1 items
  1: "AnEmptyValueNotNull"
  4: dyn_string 1 items
  1: "AnEmptyValueNotNull"
  5: dyn_string 1 items
  1: "AnEmptyValueNotNull"
  ]
  */
