  time t;
  dyn_int di;
  dyn_time dt;
  t=makeTime(1999,8,15,12,30);
  dt=makeDynTime(t,t+30,t+60,t+90,t+120,t+150,t+180);
  di=makeDynInt(1,2,3,4,5,6,7);
  DebugN("dynAvgWT:",dynAvgWT(1,dt[1],dt[7],di,dt));
}

