The following example returns the difference in coordinates between the current Panel
                and the child panel "myOtherPanel". The LogViewer will print the values
                x:-100;y:-100 as the child panel is opened with this offset.
main()
{
  int x, y;
  dyn_float resultFloat;
  dyn_string restultString;
  ChildPanelOn("about.pnl", "myOtherPanel", makeDynString(),100,100);
  while(!isPanelOpen("myOtherPanel")){}; //Wait until panel is opened
  panelPosition(myModuleName(),"myOtherPanel",x,y);
  DebugN("X",x,"Y",y);
}

