  dyn_string pattern;
  pattern = makeDynString("panels");
  /* The files from the directory "panels" will be
  delivered.*/
  mapping opt;
  opt["fromTime"] = t;
  opt["allIfOneYounger"] = TRUE;
  dyn_mapping l;
  l = requestFileList(manID, pattern, opt);
  /* Function call. Files from the directory "panels" will be
