}

Returns the value of the given node.
The meaning of the value depends on the node type that is asked.
The following node type constants are here meaningful:
ConstantMeaningXML_ATTRIBUTE_NODEAttribute valueXML_CDATA_SECTION_NODEContent of the CDATA sectionXML_COMMENT_NODECommentXML_PROCESSING_INSTRUCTION_NODEData of the processing instructionXML_TEXT_NODEText
All the other node types do not have a node value and will return an empty
                string.
Example
#uses "CtrlXml"
main()
{
  unsigned doc;
  int ret;
  int rootId;
  int nodeType;
  int childId;
  string nodeTypeText;
  doc = xmlNewDocument();
  DebugN("doc", doc);
  rootId = xmlAppendChild(doc, -1, 1);
  //Node type definition
  nodeType = XML_ATTRIBUTE_NODE;
  nodeTypeText = "Attribute name";
  //Add child
  childId = xmlAppendChild(doc, rootId, nodeType,
  "name_"+nodeTypeText);
  DebugN("xmlAppendChild", nodeTypeText + "(" + nodeType + ")",
  childId);
  //Detect node type
  DebugN("xmlNodeType", childId, nodeTypeText+"("+nodeType+")",
  xmlNodeType(doc, childId));
  //Detect node name
  DebugN("xmlNodeName", childId, nodeTypeText+"("+nodeType+")",
  xmlNodeName(doc, childId));
  //Set value
  DebugN("xmlSetNodeValue", childId, xmlSetNodeValue(doc, childId,
  "Value_"+nodeTypeText));
  //Read value
  DebugN("Read node value: ", childId, xmlNodeValue(doc,
  childId));
  //Add attribute
  DebugN("xmlSetElementAttribute", childId,
  xmlSetElementAttribute(doc, childId, "attrib",
  "att_"+nodeTypeText));
  //Read attribute
  mapping m;
  m = xmlElementAttributes(doc, childId);
  DebugN("xmlSetElementAttribute", childId, m);
  //Write to string
  DebugN("xmlDocumentToString", xmlDocumentToString(doc));
  ret = xmlCloseDocument(doc);
  DebugN(ret);
}

Returns the internal ID for the parent node of the given node.
Example
Reads the d:/XmlTest0.xml file and creates a document. The content of the document is
                printed using printNodes. The function xmlElementAttributes returns all node
                attributes as a mapping. XmlNextSibling is used to return the internal Id of the
                next sibling of a node. XmlNodeName returns the name of a node. XmlNodeType returns
                the type of the given node. xmlParentNode returns the internal ID for the parent
                node of the given node.
#uses "CtrlXml"
global uint docNum;
global string err;
global int errLine, errColumn;
main()
{
  uint node;
  DebugN(docNum = xmlDocumentFromFile("d:/XmlTest0.xml", err,
  errLine,
  errColumn));
  DebugN("error:", err, errLine, errColumn);
  printNodes(node = xmlFirstChild(docNum));
  xmlSetElementAttribute(docNum, node, "test_attribute", "some
  fancy
  value !!");
}
void printNodes(int node)
{
  if ( node != -1 )
  {
    if ( xmlNodeType(docNum, node) == XML_TEXT_NODE )
    DebugN("value:", xmlNodeValue(docNum, node));
    if ( xmlNodeType(docNum, node) == XML_ELEMENT_NODE )
    DebugN(xmlNodeName(docNum, node), xmlElementAttributes(docNum,
    node) );
    printNodes(xmlFirstChild(docNum, node));
    printNodes(xmlNextSibling(docNum, node));
    printNodes(xmlParentNode(docNum, node));
    DebugN(xmlDocumentFromFile(docNum, "d:/XmlTest0.xml",err,
    errLine,
    errColumn));
  }
}

